INSERT INTO faqs (question,answer,sort_order,active) VALUES ('¿Cómo compro?','Elegí un producto y tocá Comprar por WhatsApp. Te va a llegar un mensaje listo para consultar.',1,1);
INSERT INTO faqs (question,answer,sort_order,active) VALUES ('¿Tienen pasarela de pago online?','No. La compra se coordina únicamente por WhatsApp para darte atención personalizada.',2,1);
INSERT INTO faqs (question,answer,sort_order,active) VALUES ('¿Cómo elijo el talle?','En cada producto podés ver talles disponibles y una guía simple de medidas.',3,1);
INSERT INTO faqs (question,answer,sort_order,active) VALUES ('¿Hacen envíos?','Los envíos o entregas se coordinan por mensaje según tu zona.',4,1);
